// Price = Base Price + Availability Adjustment + Battery Level Adjustment
// Availability = (generation - demand - reservedEnergy)
// Availability Ratio = (availableEnergy / maxCapacity) * 100
// Availability Adjustment = price adjustment based on availability ratio
// Battery Level Adjustment = price adjustment based on battery level

library PricingLibrary{
function c_3f4353dd(bytes8 c__3f4353dd) internal pure {}
function c_true3f4353dd(bytes8 c__3f4353dd) internal pure returns (bool){ return true; }
function c_false3f4353dd(bytes8 c__3f4353dd) internal pure returns (bool){ return false; }

    uint256 constant BASE_PRICE = 10; // 10 ETK/kWh

    uint256 constant HIGH_SURPLUS_DISC = 2;
    uint256 constant MID_SURPLUS_DISC = 1;

    uint256 constant LOW_SURPLUS_PREMIUM = 2;
    uint256 constant DEFICIT_SURPLUS_PREMIUM = 4;

    uint256 constant HIGH_BATTERY_DISC = 2;
    uint256 constant MID_BATTERY_DISC = 1;

    uint256 constant LOW_BATTERY_PREMIUM = 2;
    uint256 constant DEFICIT_BATTERY_PREMIUM = 4;

    function calculatePrice(
        uint256 generation, 
        uint256 demand, 
        uint256 batteryLevel, 
        uint256 maxCapacity, 
        uint256 reservedEnergy
    ) internal pure returns (uint256){c_3f4353dd(0xe59e2c24b4122ea6); /* function */ 

c_3f4353dd(0x552507d86d11d6f4); /* line */ 
        c_3f4353dd(0x279d5edce02d8f96); /* statement */ 
uint256 price = BASE_PRICE;

c_3f4353dd(0x42333b8d06f3359a); /* line */ 
        c_3f4353dd(0x1529075b9e3902c7); /* statement */ 
int256 availableEnergy = int256(generation) - int256(demand) - int256(reservedEnergy);
c_3f4353dd(0x96d12ff52e8668e6); /* line */ 
        c_3f4353dd(0x795d5357bd5d35b7); /* statement */ 
int256 availabilityRatio = (availableEnergy * 100) / int256(maxCapacity);

        // availability adjustments
c_3f4353dd(0xf535f76c476c0ce8); /* line */ 
        c_3f4353dd(0xccaa71e57007eec2); /* statement */ 
if(availabilityRatio >= 70) {c_3f4353dd(0x93850a2aae92b54d); /* branch */ 
price -= HIGH_SURPLUS_DISC;}
        else {c_3f4353dd(0x8a313710a197347a); /* statement */ 
c_3f4353dd(0x186b9ea3f93e06db); /* branch */ 
if(availabilityRatio >= 40) {c_3f4353dd(0x290dadfe08a73667); /* branch */ 
price -= MID_SURPLUS_DISC;}
        else {c_3f4353dd(0x3d45e1ae604e45d9); /* statement */ 
c_3f4353dd(0xf83617716c1214ab); /* branch */ 
if(availabilityRatio >= 20) {c_3f4353dd(0x2bc5e0315f8cea63); /* branch */ 
}
        else {c_3f4353dd(0x2a26f29228ac594d); /* statement */ 
c_3f4353dd(0x3a793d3aeab69873); /* branch */ 
if(availabilityRatio >= 0) {c_3f4353dd(0xbf95e14ccb94ecf3); /* branch */ 
price += LOW_SURPLUS_PREMIUM;}
        else {c_3f4353dd(0xbee89ec3da9e19ea); /* branch */ 
price += DEFICIT_SURPLUS_PREMIUM;}}}}

        // battery level adjustments
c_3f4353dd(0xb917fc5d75309477); /* line */ 
        c_3f4353dd(0xbb9b3434d27d43b7); /* statement */ 
if(batteryLevel >= 80) {c_3f4353dd(0x60d7bbb0c4742de7); /* branch */ 
price -= HIGH_BATTERY_DISC;}
        else {c_3f4353dd(0x406bd57269fe0c33); /* statement */ 
c_3f4353dd(0x89b58ed4a8201f3e); /* branch */ 
if(batteryLevel >= 60) {c_3f4353dd(0xa409d1592cb9e8b6); /* branch */ 
price -= MID_BATTERY_DISC;}
        else {c_3f4353dd(0xb7a5e097c422c285); /* statement */ 
c_3f4353dd(0xe1050fd692e780a5); /* branch */ 
if(batteryLevel >= 40) {c_3f4353dd(0xe92a29f9318a9fef); /* branch */ 
}
        else {c_3f4353dd(0x7b0960d25ca89532); /* statement */ 
c_3f4353dd(0x1fb24eba70863702); /* branch */ 
if(batteryLevel >= 20) {c_3f4353dd(0xfaf6c96db548ca71); /* branch */ 
price += LOW_BATTERY_PREMIUM;}
        else {c_3f4353dd(0xe8fe5d37cefb08e9); /* branch */ 
price += DEFICIT_BATTERY_PREMIUM;}}}}

c_3f4353dd(0x44713e3ecee556b9); /* line */ 
        c_3f4353dd(0x58a31924b2ce1387); /* statement */ 
if(price < 1) {c_3f4353dd(0x32ac1783bb292362); /* branch */ 
price = 1;}else { c_3f4353dd(0x9a08181c36be1af2); /* branch */ 
}

c_3f4353dd(0xc87d3ea6698cabf2); /* line */ 
        c_3f4353dd(0xca3fa540c53f2ea9); /* statement */ 
return price;
    }

    function calculateCost(uint256 _price, uint256 _amt) internal pure returns (uint256) {c_3f4353dd(0xe112cfa0e6d236eb); /* function */ 

c_3f4353dd(0xc6b37b89e14ae6d9); /* line */ 
        c_3f4353dd(0x3bd7961d41f8b64b); /* requirePre */ 
